const functions = require('@google-cloud/functions-framework');
const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

function getEnv(name, required = true) {
  const value = process.env[name];
  if (required && (!value || !value.trim())) {
    throw new Error(`Missing required environment variable: ${name}`);
  }
  return value;
}

function initSendGrid() {
  const apiKey = getEnv('SENDGRID_API_KEY');
  sgMail.setApiKey(apiKey);
}

function initTwilio() {
  const accountSid = getEnv('TWILIO_ACCOUNT_SID');
  const authToken = getEnv('TWILIO_AUTH_TOKEN');
  const fromNumber = getEnv('TWILIO_FROM_NUMBER');
  return {
    client: twilio(accountSid, authToken),
    fromNumber,
  };
}

async function sendEmail(payload) {
  const from = payload.from || getEnv('SENDGRID_FROM_EMAIL');
  const to = payload.to;
  const subject = payload.subject || '';
  const text = payload.text || '';
  const html = payload.html;

  if (!to) throw new Error('Missing "to" for email');
  if (!subject) throw new Error('Missing "subject" for email');
  if (!text && !html) throw new Error('Email must include "text" or "html"');

  const msg = {
    to,
    from,
    subject,
    text: text || undefined,
    html: html || undefined,
  };

  const response = await sgMail.send(msg);
  return {
    success: true,
    service: 'sendgrid',
    statusCode: response?.[0]?.statusCode || 202,
  };
}

async function sendSms(payload) {
  const { client, fromNumber } = initTwilio();
  const to = payload.to;
  const body = payload.body;

  if (!to) throw new Error('Missing "to" for sms');
  if (!body) throw new Error('Missing "body" for sms');

  const message = await client.messages.create({
    to,
    from: payload.from || fromNumber,
    body,
  });

  return {
    success: true,
    service: 'twilio',
    sid: message.sid,
    status: message.status,
  };
}

function parseRequest(req) {
  if (req.method === 'GET') {
    return {
      type: req.query.type,
      to: req.query.to,
      subject: req.query.subject,
      text: req.query.text,
      html: req.query.html,
      body: req.query.body,
      from: req.query.from,
    };
  }

  const body = typeof req.body === 'object' && req.body !== null ? req.body : {};
  return {
    type: body.type,
    to: body.to,
    subject: body.subject,
    text: body.text,
    html: body.html,
    body: body.body,
    from: body.from,
  };
}

functions.http('notify', async (req, res) => {
  try {
    if (req.method !== 'GET' && req.method !== 'POST') {
      res.status(405).json({ success: false, error: 'Method not allowed' });
      return;
    }

    initSendGrid();

    const payload = parseRequest(req);
    const type = (payload.type || '').toLowerCase();

    if (!type) {
      res.status(400).json({ success: false, error: 'Missing "type" (email or sms)' });
      return;
    }

    let result;
    if (type === 'email') {
      result = await sendEmail(payload);
    } else if (type === 'sms' || type === 'text') {
      result = await sendSms(payload);
    } else {
      res.status(400).json({ success: false, error: 'Invalid "type". Use "email" or "sms"' });
      return;
    }

    res.status(200).json(result);
  } catch (error) {
    console.error(error);

    const message = error && error.message ? error.message : 'Internal server error';
    const status = /missing|required|invalid/i.test(message) ? 400 : 500;

    res.status(status).json({
      success: false,
      error: message,
    });
  }
});